import { SmsMessageType } from '../../rest/api';
import { BASEPATH, PASSWORD, USERNAME } from '../config';
import { SmsService } from './sms.wrapper';
describe('sms', () => {
    let service;
    beforeAll(async () => {
        service = new SmsService({
            username: USERNAME,
            password: PASSWORD,
            basePath: BASEPATH,
        }, true);
    });
    it(`sms.send`, () => {
        const response = service.send({
            type: SmsMessageType.SMS,
            from: '01053601894',
            to: ['01053601894'],
            message: `센드온SDK를 이용한 문자 발송입니다.(${Math.random().toString(36).substring(2, 5)})`,
        });
        expect(response).toBeDefined();
    });
    it(`sms.sendExcel`, () => { });
    it(`sms.cancel`, () => { });
    it(`sms.find`, () => { });
    it(`sms.getMmsImageUrl`, () => { });
    it(`sms.uploadExcel`, () => { });
    it(`sms.uploadImages`, () => { });
});
